Recursion:
fun factorial(n) {
  if (n <= 1) return 1;
  return n * factorial(n - 1);
}

print "Factorial of 5:";
print factorial(5);

fun fib(n) {
  if (n <= 1) return n;
  return fib(n - 1) + fib(n - 2);
}

print "Fibonacci sequence (0 to 9):";
for (var i = 0; i < 10; i = i + 1) {
  print fib(i);
}
